"use no memo";

import {
  ArrowDown,
  ArrowDownAZ,
  ArrowUp,
  ArrowUpDown,
  ArrowUpZA,
  EyeOff,
} from "lucide-react";
import { Fragment, type ReactNode } from "react";

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { cn } from "@/lib/utils";
import { slugToTitle } from "@/components/fsui/fscommon";

import type { Column, Header } from "@tanstack/react-table";

interface FsTableColumnHeaderProps<TData, TValue> {
  className?: string;
  column: Column<TData, TValue>;
  title?: ReactNode;
}

export const FsTableHeaderResizer = <T,>({
  header,
  isLast,
}: {
  header: Header<T, unknown>;
  isLast?: boolean;
}) => {
  if (!header.column.getCanResize()) {
    return isLast ? null : (
      <div className="group absolute top-0 right-1 flex h-full w-[1px] touch-none items-center align-middle select-none">
        <div className="bg-border h-[18px] w-[1px] touch-none select-none" />
      </div>
    );
  }

  return (
    <div className="absolute right-2 flex h-full w-[2px] touch-none items-center justify-center select-none">
      <div
        {...{
          onDoubleClick: () => header.column.resetSize(),
          onMouseDown: header.getResizeHandler(),
          onTouchStart: header.getResizeHandler(),
          className:
            "after:-translate-x-1/2 z-50 h-[18px] w-[1px] hover:w-[2px] focus:w-[2px] cursor-ew-resize touch-none select-none bg-border transition-opacity after:absolute after:inset-y-0 after:start-1/2 after:h-[24px] after:w-[18px] after:content-[''] hover:bg-primary focus:bg-primary focus:outline-none",
        }}
      />
    </div>
  );
};

export function FsTableColumnHeader<TData, TValue>({
  column,
  title,
  className,
}: FsTableColumnHeaderProps<TData, TValue>) {
  title = title ?? slugToTitle(column.id);
  if (!column.getCanSort()) {
    return <div className={cn(className)}>{title}</div>;
  }

  const isDragging = column.getIsResizing();

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant="ghost"
          size="sm"
          className={cn(
            "data-[state=open]:bg-accent relative -ml-2 flex h-8 w-full flex-row justify-between select-none",
            className,
            isDragging && "pointer-events-none",
          )}
        >
          <span>{title}</span>
          {column.getIsSorted() === "desc" ? (
            <ArrowUpZA className="text-muted-foreground size-3.5" />
          ) : column.getIsSorted() === "asc" ? (
            <ArrowDownAZ className="text-muted-foreground size-3.5" />
          ) : (
            <ArrowUpDown className="text-muted-foreground size-3.5" />
          )}
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="start">
        <DropdownMenuItem onClick={() => column.toggleSorting(false)}>
          <ArrowUp className="text-muted-foreground/70 h-3.5 w-3.5" />
          Asc
        </DropdownMenuItem>
        <DropdownMenuItem onClick={() => column.toggleSorting(true)}>
          <ArrowDown className="text-muted-foreground/70 h-3.5 w-3.5" />
          Desc
        </DropdownMenuItem>
        {column.getCanHide() && (
          <Fragment>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={() => column.toggleVisibility(false)}>
              <EyeOff className="text-muted-foreground/70 h-3.5 w-3.5" />
              Hide
            </DropdownMenuItem>
          </Fragment>
        )}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

