import { Settings2 } from "lucide-react";

import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";

import type { Table } from "@tanstack/react-table";

export function FsTableViewOptions<TData>({ table }: { table: Table<TData> }) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant="outline"
          size="sm"
          className="ml-auto hidden h-8 lg:flex"
        >
          <Settings2 />
          View
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent
        align="end"
        className="w-[150px]"
      >
        <DropdownMenuLabel>Toggle columns</DropdownMenuLabel>
        <DropdownMenuSeparator />
        {table
          .getAllColumns()
          .filter(
            (column) => column.accessorFn !== undefined && column.getCanHide(),
          )
          .map((column) => {
            return (
              <DropdownMenuCheckboxItem
                key={column.id}
                className="capitalize"
                checked={column.getIsVisible()}
                onCheckedChange={(value) => column.toggleVisibility(!!value)}
              >
                {column.id}
              </DropdownMenuCheckboxItem>
            );
          })}
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

import { flexRender, type Table } from "@tanstack/react-table";

import { cn } from "@/lib/utils";

import { FsTableHeaderResizer } from "./column-header";

export const FsTableHead = <TData,>({
  table,
  className,
}: {
  table: Table<TData>;
  className?: string;
}) => {
  return (
    <div
      data-slot="table-header"
      className={className}
    >
      {table.getHeaderGroups().map((headerGroup) => (
        <div
          data-slot="table-header-row"
          className="hover:bg-muted/50 data-[state=selected]:bg-muted border-b transition-colors"
          key={headerGroup.id}
        >
          {headerGroup.headers.map((header, i) => {
            const isLast = i === headerGroup.headers.length - 1;
            return (
              <div
                key={header.id}
                data-slot="table-header-cell"
                style={{
                  width: `calc(var(--header-${header?.id}-size) * 1px)`,
                }}
                className={
                  "text-foreground relative inline-flex h-10 items-center px-2 text-left align-middle font-medium whitespace-nowrap [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]"
                }
              >
                {header.isPlaceholder
                  ? null
                  : flexRender(
                      header.column.columnDef.header,
                      header.getContext(),
                    )}
                <FsTableHeaderResizer
                  header={header}
                  isLast={isLast}
                />
              </div>
            );
          })}
        </div>
      ))}
    </div>
  );
};

export const FsTableBody = <TData,>({
  table,
  className,
}: {
  table: Table<TData>;
  className?: string;
}) => {
  return (
    <div
      data-slot="table-body"
      className={cn("[&_div:last-child]:border-0", className)}
    >
      {table.getRowModel().rows?.length ? (
        table.getRowModel().rows.map((row) => {
          return (
            <div
              key={row.id}
              data-slot="table-row"
              data-state={row.getIsSelected() && "selected"}
              className="hover:bg-muted/50 data-[state=selected]:bg-muted odd:bg-background even:bg-muted/40 border-b transition-colors"
            >
              {row.getVisibleCells().map((cell) => (
                <div
                  data-slot="table-cell"
                  className="inline-flex items-center p-2 align-middle [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]"
                  key={cell.id}
                  style={{
                    width: `calc(var(--col-${cell.column.id}-size) * 1px)`,
                  }}
                >
                  {flexRender(cell.column.columnDef.cell, cell.getContext())}
                </div>
              ))}
            </div>
          );
        })
      ) : (
        <div className="hover:bg-muted/50 data-[state=selected]:bg-muted border-b transition-colors">
          <div className="p-2 text-center align-middle whitespace-nowrap [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]">
            No results.
          </div>
        </div>
      )}
    </div>
  );
};

export const FsTableBodyGrid = <TData,>({
  table,
  className,
}: {
  table: Table<TData>;
  className?: string;
}) => {
  return (
    <div
      data-slot="table-body"
      className={cn("grid grid-cols-4 gap-4", className)}
    >
      {table.getRowModel().rows?.length ? (
        table.getRowModel().rows.map((row) => {
          return (
            <div
              key={row.id}
              data-slot="table-row"
              data-state={row.getIsSelected() && "selected"}
              className="group flex cursor-pointer flex-col gap-2"
            >
              {row.getVisibleCells().map((cell) => (
                <div
                  data-slot="table-cell"
                  className="inline-flex items-center p-2 align-middle [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]"
                  key={cell.id}
                  style={{
                    width: `calc(var(--col-${cell.column.id}-size) * 1px)`,
                  }}
                >
                  {flexRender(cell.column.columnDef.cell, cell.getContext())}
                </div>
              ))}
            </div>
          );
        })
      ) : (
        <div className="hover:bg-muted/50 data-[state=selected]:bg-muted border-b transition-colors">
          <div className="p-2 text-center align-middle whitespace-nowrap [&:has([role=checkbox])]:pr-0 [&>[role=checkbox]]:translate-y-[2px]">
            No results.
          </div>
        </div>
      )}
    </div>
  );
};

export const FsTableWrapper = <TData,>({
  table,
  columnSizeVars,
  className,
}: {
  table: Table<TData>;
  columnSizeVars: Record<string, number>;
  className?: string;
}) => {
  return (
    <div className={cn("w-full rounded-md border", className)}>
      <div
        data-slot="table-container"
        className="relative w-full overflow-x-auto"
      >
        <div
          data-slot="table"
          className="w-full caption-bottom text-sm"
          style={{
            ...columnSizeVars,
            width: table.getTotalSize(),
            minWidth: "100%",
          }}
        >
          <FsTableHead table={table} />
          <FsTableBody table={table} />
        </div>
      </div>
    </div>
  );
};

