import { cn } from "@/lib/utils";

import { FsTableWrapper } from "./common";
import { useFsTable, type UseFsTableParams } from "./use-fstable";
import { FsTablePagination } from "./pagination";
import { FsTableToolbar } from "./toolbar";

import type { ReactNode } from "react";

export interface FsTableProps<TData, TValue>
  extends UseFsTableParams<TData, TValue> {
  className?: string;
  actions?: {
    left?: ReactNode;
    right?: ReactNode;
  };
}

export function FsTable<TData, TValue>({
  className,
  actions,
  ...props
}: FsTableProps<TData, TValue>) {
  const { table, columnSizeVars } = useFsTable<TData, TValue>(props);

  return (
    <div className={cn("max-w-full space-y-4", className)}>
      <FsTableToolbar
        table={table}
        actions={actions}
      />
      <FsTableWrapper
        table={table}
        columnSizeVars={columnSizeVars}
      />
      <FsTablePagination table={table} />
    </div>
  );
}

