import {
  getCoreRowModel,
  getFacetedRowModel,
  getFacetedUniqueValues,
  getFilteredRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
  type ColumnDef,
  type ColumnFiltersState,
  type Row,
  type RowSelectionState,
  type SortingState,
  type TableOptions,
  type TableState,
  type Updater,
  type VisibilityState,
} from "@tanstack/react-table";
import { useMemo, useState } from "react";

import type { PKType } from "fastschema";

export interface UseFsTableParams<TData, TValue> {
  data: TData[];
  columns: ColumnDef<TData, TValue>[];
  pagination?: {
    totalItems: number;
    itemsPerPage: number;
    currentPage: number;
    totalPages: number;
    onChange?: (page: number, limit: number) => void;
  };
  getRowId?: (originalRow: TData, index: number, parent?: Row<TData>) => PKType;
  onRowSelectionChange?: (selectedRowIds: Record<PKType, boolean>) => void;
  multiSelection?: boolean;
}

export const useFsTable = <TData, TValue>({
  pagination,
  data,
  columns,
  getRowId,
  onRowSelectionChange,
  multiSelection = true,
}: UseFsTableParams<TData, TValue>) => {
  const [rowSelection, setRowSelection] = useState<Record<PKType, boolean>>(
    {} as Record<PKType, boolean>,
  );
  const [columnVisibility, setColumnVisibility] = useState<VisibilityState>({});
  const [columnFilters, setColumnFilters] = useState<ColumnFiltersState>([]);
  const [sorting, setSorting] = useState<SortingState>([]);
  const { currentPage = 1, itemsPerPage = 10 } = pagination || {};

  const handleRowSelectionChange = (
    updaterOrValue: Updater<RowSelectionState>,
  ) => {
    let newState =
      typeof updaterOrValue === "function"
        ? updaterOrValue(rowSelection)
        : updaterOrValue;

    if (!multiSelection) {
      const selectedKeys = Object.keys(newState).filter((key) => newState[key]);
      if (selectedKeys.length > 1) {
        const newlySelected = selectedKeys.find((key) => !rowSelection[key]);
        newState = newlySelected ? { [newlySelected]: true } : {};
      }
    }

    setRowSelection(newState as Record<PKType, boolean>);
    onRowSelectionChange?.(newState as Record<PKType, boolean>);
  };

  const manualPagination = pagination?.totalPages !== undefined;
  const tableOptions: TableOptions<TData> = {
    data,
    columns,
    initialState: {},
    state: {
      sorting,
      columnVisibility,
      rowSelection,
      columnFilters,
    },
    getRowId: getRowId as TableOptions<TData>["getRowId"],
    enableRowSelection: true,
    columnResizeMode: "onChange",
    defaultColumn: {
      size: 100, //starting column size
      minSize: 50, //enforced during column resizing
      maxSize: 500, //enforced during column resizing
    },
    manualPagination,
    pageCount: pagination?.totalPages,
    rowCount: pagination?.totalItems,
    onRowSelectionChange: handleRowSelectionChange,
    onSortingChange: setSorting,
    onColumnFiltersChange: setColumnFilters,
    onColumnVisibilityChange: setColumnVisibility,
    getCoreRowModel: getCoreRowModel(),
    getFilteredRowModel: getFilteredRowModel(),
    getPaginationRowModel: getPaginationRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getFacetedRowModel: getFacetedRowModel(),
    getFacetedUniqueValues: getFacetedUniqueValues(),
  };

  if (manualPagination) {
    const paginationState = {
      pageIndex: currentPage - 1 || 0,
      pageSize: itemsPerPage || 10,
    };
    (tableOptions.state as Partial<TableState>).pagination = paginationState;
    tableOptions.onPaginationChange = (updater) => {
      const newState =
        typeof updater === "function" ? updater(paginationState) : updater;
      pagination?.onChange?.(newState.pageIndex + 1, newState.pageSize);
    };
  }

  const table = useReactTable(tableOptions);
  const columnSizeVars = useMemo(() => {
    const headers = table.getFlatHeaders();
    const colSizes: Record<string, number> = {};
    for (const header of headers) {
      colSizes[`--header-${header.id}-size`] = header.getSize();
      colSizes[`--col-${header.column.id}-size`] = header.column.getSize();
    }
    return colSizes;
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [table.getState().columnSizingInfo, table.getState().columnSizing]);

  return {
    table,
    columnSizeVars,
  };
};

